import { Link } from "react-router-dom";
import { ArrowLeft } from "lucide-react";

/**
 * Gradient Modern gateway card - vibrant gradient design
 * Props: { to, label, description, icon: Icon, count, countSuffix, accent: "blue|amber|emerald|rose|violet|sky" }
 */
const ACCENT_GRADIENTS = {
  blue:    { from: "from-blue-600", to: "to-blue-900", shadow: "shadow-blue-500/50" },
  amber:   { from: "from-amber-500", to: "to-orange-600", shadow: "shadow-amber-500/50" },
  emerald: { from: "from-emerald-500", to: "to-teal-700", shadow: "shadow-emerald-500/50" },
  rose:    { from: "from-rose-500", to: "to-pink-700", shadow: "shadow-rose-500/50" },
  violet:  { from: "from-violet-500", to: "to-purple-700", shadow: "shadow-violet-500/50" },
  sky:     { from: "from-sky-500", to: "to-cyan-700", shadow: "shadow-sky-500/50" },
};

export default function GatewayCard({ to, label, description, icon: Icon, count = 0, countSuffix = "سجل", accent = "blue", testIdKey }) {
  const gradient = ACCENT_GRADIENTS[accent] || ACCENT_GRADIENTS.blue;

  return (
    <Link
      to={to}
      className={`group relative block overflow-hidden rounded-2xl bg-gradient-to-br ${gradient.from} ${gradient.to} p-6 shadow-lg ${gradient.shadow} transition-all duration-500 hover:scale-[1.02] hover:shadow-2xl`}
      data-testid={`gateway-card-${testIdKey}`}
    >
      {/* Glassmorphism overlay */}
      <div className="absolute inset-0 bg-white/5 backdrop-blur-[1px]" />

      {/* Content */}
      <div className="relative">
        {/* Header: Icon + Count */}
        <div className="flex items-start justify-between gap-4">
          <div className="grid h-16 w-16 flex-shrink-0 place-items-center rounded-xl bg-white/20 backdrop-blur-sm" data-testid={`gateway-card-icon-${testIdKey}`}>
            {Icon ? <Icon className="h-8 w-8 text-white" /> : null}
          </div>
          <div className="rounded-full bg-white/90 px-4 py-2 backdrop-blur-sm" data-testid={`gateway-card-count-${testIdKey}`}>
            <div className="text-center text-lg font-extrabold text-slate-900">
              {count.toLocaleString('ar-EG')}
            </div>
            <div className="text-[10px] font-bold text-slate-600">
              {countSuffix}
            </div>
          </div>
        </div>

        {/* Title & Description */}
        <div className="mt-6">
          <h3 className="text-2xl font-extrabold text-white drop-shadow-md" data-testid={`gateway-card-title-${testIdKey}`}>
            {label}
          </h3>
          {description && (
            <p className="mt-2 text-sm leading-relaxed text-white/90" data-testid={`gateway-card-desc-${testIdKey}`}>
              {description}
            </p>
          )}
        </div>

        {/* CTA Button */}
        <div className="mt-6">
          <div className="inline-flex items-center gap-2 rounded-lg bg-white px-6 py-3 text-sm font-bold text-slate-900 shadow-lg transition-all duration-300 group-hover:shadow-xl group-hover:scale-105" data-testid={`gateway-card-open-${testIdKey}`}>
            <span>عرض السجلات</span>
            <ArrowLeft className="h-4 w-4 transition-transform duration-300 group-hover:-translate-x-1" />
          </div>
        </div>
      </div>

      {/* Shine effect on hover */}
      <div className="absolute -inset-full top-0 block h-full w-1/2 -skew-x-12 transform bg-gradient-to-r from-transparent to-white opacity-20 transition-all duration-700 group-hover:left-full" />
    </Link>
  );
}
